  signal rst            : std_logic := '0';
  signal n              : integer range 1 to n_max;
  signal sort_en        : std_logic;
  signal LLR_mag        : std_logic_vector(n_max * B_mag - 1 downto 0);
  signal sorted_indices : std_logic_vector(LW_MAX * WIDTH_INDICES - 1 downto 0);
